function [x,y,roiImg] = fImgROIV01(x,y,img,fct)%% ROi image based on factor%% [x,y,roiImg] = fImgRoiV01(x,y,img,fct)%% x,y: axis information% img, roiImg: input and ROI image% fct: factor for ROI% image ROi, ver.1%% Written by Kei Nakamura% Created on Friday, March 25th 2011.% Modified on%% horizontalvSum = sum(img);    % vertically summed[pk,pkIdx] = max(vSum);   % peak, peak indexj1 = find(vSum(1:pkIdx)<fct*pk,1,'last');j2 = find(vSum(pkIdx:end)<fct*pk,1,'first')+pkIdx-1;   % index for x% edge%% verticalhSum = sum(img,2);  % horizontally summed[pk,pkIdx] = max(hSum);k1 = find(hSum(1:pkIdx)<fct*pk,1,'last');k2 = find(hSum(pkIdx:end)<fct*pk,1,'first')+pkIdx-1;   % index for x% edge+lgc = numel(k1)~=0 && numel(k2)~=0 && numel(j1)~=0 && numel(j2)~=0 && sum(sum(img))~=0;if lgc    if (k2-k1)*(j2-j1)>30        roiImg = img(k1:k2,j1:j2);        x = x(:,j1:j2);         y = y(:,k1:k2);    else        roiImg = img;    endelse    roiImg = img;end
